**Recommendation:** Require auth and scope access. Example with a JWT middleware:

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const token = header.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) return res.status(401).json({ error: 'unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

function requireRole(role) {
  return (req, res, next) =>
    req.user?.roles?.includes(role) ? next() : res.status(403).json({ error: 'forbidden' });
}

app.get('/users', requireAuth, requireRole('admin'), (req, res) => { ... });
```

Also consider returning **only the fields the caller needs** (don't leak email unless required) — this addresses A02:2021 (Cryptographic/Sensitive Data) and A04:2021 (Insecure Design).

---

### 2. Missing Security Headers — **High** (OWASP A05:2021 Security Misconfiguration)

No `helmet`, no CSP, no HSTS, no `X-Content-Type-Options`, no `Referrer-Policy`. Express ships insecure defaults (e.g., `X-Powered-By: Express` is sent, fingerprinting the server).

**Recommendation:**

```js
const helmet = require('helmet');
app.disable('x-powered-by');
app.use(helmet({
  contentSecurityPolicy: { directives: { defaultSrc: ["'self'"] } },
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true },
  referrerPolicy: { policy: 'no-referrer' },
}));
```

