**Fix — require auth and, ideally, scope the response to the caller:**

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.get('authorization') || '';
  const [scheme, token] = header.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return res.status(401).json({ error: 'unauthorized' });
  }
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET, { algorithms: ['HS256'] });
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

app.get('/users', requireAuth, (req, res) => {
  // Consider returning only non-sensitive fields unless caller is an admin
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});
```

Never pull the JWT secret from a hardcoded string; require `process.env.JWT_SECRET` and fail fast at startup if missing.

---

### 2. Missing security headers (Medium — A05)

Express ships with none of the standard hardening headers (CSP, HSTS, `X-Content-Type-Options`, `Referrer-Policy`, etc.).

**Fix — use `helmet` and remove the `X-Powered-By` fingerprint:**

```js
