## 7. No input validation layer scaffolded — **Medium** (A03: Injection)

Currently no inputs, but add a schema validator before endpoints accept any so developers can't ship an unvalidated route.

```js
const { z } = require('zod');

function validate(schema) {
  return (req, res, next) => {
    const result = schema.safeParse({ body: req.body, query: req.query, params: req.params });
    if (!result.success) return res.status(400).json({ error: result.error.flatten() });
    req.valid = result.data;
    next();
  };
}

// Example usage when you add a route:
const getUserSchema = z.object({
  params: z.object({ id: z.coerce.number().int().positive() }),
});
app.get('/users/:id', validate(getUserSchema), (req, res) => { /* ... */ });
```

