  res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }, ...]);
});
```

**Recommendation** — require auth and scope the response:
```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const token = header.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) return res.status(401).json({ error: 'unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

app.get('/users', requireAuth, (req, res) => {
  // Don't leak emails unless the caller is authorized to see them
  res.json(users.map(u => ({ id: u.id, name: u.name })));
});
```

### 2. `X-Powered-By: Express` header leaks framework (OWASP A05: Security Misconfiguration)
Express sets this by default. It helps attackers target known CVEs.

```js
app.disable('x-powered-by');
```

### 3. No security headers — use `helmet` (OWASP A05)
Missing `Content-Security-Policy`, `X-Content-Type-Options: nosniff`, `Strict-Transport-Security`, `X-Frame-Options`, `Referrer-Policy`, etc.

```js
const helmet = require('helmet');
app.use(helmet());
```

### 4. No CORS policy configured (OWASP A05)
Browsers will block cross-origin by default, but once a frontend is added this tends to get set to `*`. Lock it down explicitly now:

```js
const cors = require('cors');
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean),
  credentials: true,
}));
```

### 5. No rate limiting (OWASP A04: Insecure Design / A07: ID & Auth Failures)
Any endpoint is trivially floodable. Add a limiter before you add login or write endpoints:

```js
const rateLimit = require('express-rate-limit');
app.use(rateLimit({ windowMs: 60_000, max: 100, standardHeaders: true, legacyHeaders: false }));
```

### 6. `app.listen(3000)` binds to all interfaces (OWASP A05)
In container/dev environments this may be fine; in shared hosts it exposes the service to every interface. Bind explicitly and make the port configurable:

```js
const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '127.0.0.1';
app.listen(PORT, HOST, () => console.log(`Server running on ${HOST}:${PORT}`));
```

### 7. No error-handling middleware (OWASP A05 / A09)
An uncaught error will send Express's default stack trace to the client in dev mode and produce unstructured logs. Add a terminal error handler:

```js
app.use((err, req, res, _next) => {
  console.error({ msg: 'unhandled', err: err.message, stack: err.stack });
  res.status(500).json({ error: 'internal_error' });
});

