const rateLimit = require('express-rate-limit');
app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));
```

### 4. No CORS configuration (Low–Medium)

If a browser app will call this API, add an **allowlist**, not `*`:

```js
