    next();
  } catch {
    return res.status(401).json({ error: 'Invalid token' });
  }
}

app.get('/users', requireAuth, (req, res) => { /* ... */ });
```

### 3. Hardcoded port, no host binding, no TLS (Low-Medium)
**OWASP: A02:2021 – Cryptographic Failures**

`app.listen(3000)` binds to `0.0.0.0` by default and serves plaintext HTTP. The port is also hardcoded, which hurts configurability in containers.

**Recommendation:**
